example.code:
use proptest::prelude::*;

proptest! {
    // Round-trip invariant: parse(serialize(x)) == x
    #[test]
    fn round_trip_serialization(input in any::<ValidAst>()) {
        let serialized = serialize(&input);
        let parsed = parse(&serialized).expect("should parse serialized output");
        prop_assert_eq!(input, parsed);
    }

    // No-panic invariant: parse never panics on arbitrary bytes
    #[test]
    fn parse_never_panics(data in prop::collection::vec(any::<u8>(), 0..=1024)) {
        // We don't care about the result, only that it doesn't panic
        let _ = parse_bytes(&data);
    }
}
